// Save last exchange to static data for conversation context
try {
  const ctx = $('Schema Validator').first().json;
  const chatId = ctx.chatId || $('Identity Router').first().json.chatId;
  const userMsg = $('Identity Router').first().json.text || '';
  if (chatId && userMsg && ctx.action && ctx.action !== 'unknown') {
    const staticData = $getWorkflowStaticData('global');
    if (!staticData.conversationHistory) staticData.conversationHistory = {};
    staticData.conversationHistory[chatId] = {
      userMessage: userMsg,
      action: ctx.action,
      payload: ctx.payload || {},
      ts: Date.now()
    };
    // Keep max 50 chat histories to avoid bloat
    const keys = Object.keys(staticData.conversationHistory);
    if (keys.length > 50) {
      const oldest = keys.sort((a,b) => (staticData.conversationHistory[a].ts||0) - (staticData.conversationHistory[b].ts||0))[0];
      delete staticData.conversationHistory[oldest];
    }
  }
} catch(e) { /* non-fatal */ }

// Audit log — non-fatal: a crash here must never kill the flow
const ctx = items[0].json;
let actionCtx = {};
try { actionCtx = $('Schema Validator').first().json || {}; } catch(e) {}
try {
  const sd = $getWorkflowStaticData('global');
  if (!sd.auditLog) sd.auditLog = [];
  sd.auditLog.push({
    ts: new Date().toISOString(),
    user: actionCtx.tier || ctx.tier || '?',
    action: actionCtx.action || ctx.action || '?',
    result: ctx.error ? 'error' : 'success',
    n8nExecutionId: $execution.id,
  });
  if (sd.auditLog.length > 500) sd.auditLog = sd.auditLog.slice(-500);
} catch(e) {}
// Pass through: use summary from Format Response or fall back to humanReadableSummary
const summary = ctx.summary || actionCtx.humanReadableSummary || '✅ Completado.';
return [{ json: { ...ctx, summary, chatId: ctx.chatId || actionCtx.chatId } }];

const apiResp = items[0].json;
const ctx = $('Schema Validator').first().json;
const action = ctx.action || '';
const today = new Date().toISOString().split('T')[0];
const p = ctx.payload || {};
const requestedDate = p.date || p.startDate || today;
const endDate = p.endDate || requestedDate;

const roomNames = {662792:'Torre Badum',662793:'Cala El Pebret',662794:'Cala Aljub',662795:'Ermita Sant Antoni'};
const channelEmoji = (ch) => ch === 'bookingdotcom' ? '🌐 Booking' : ch === 'airbnb' ? '🏠 Airbnb' : '✉️ Directo';
const dateLabel = (d) => d === today ? 'hoy' : d;

let summary = '';

// ── beds24.getOccupancy ───────────────────────────────────────────────────
if (action === 'beds24.getOccupancy') {
  const rooms = apiResp.data || [];
  if (!rooms.length) { summary = '📊 No se encontraron datos de ocupación.'; }
  else {
    const lines = rooms.map(room => {
      const avail = room.availability || {};
      const s = avail[requestedDate] ?? avail[today];
      const status = s === true ? '🟢 Libre' : s === false ? '🔴 Ocupada' : '❓';
      return `• ${room.name}: ${status}`;
    });
    summary = `📊 Ocupación ${dateLabel(requestedDate)}:\n` + lines.join('\n');
  }

// ── beds24.getPrices ─────────────────────────────────────────────────────
} else if (action === 'beds24.getPrices') {
  const roomCalendars = apiResp.data || [];
  if (!roomCalendars.length) { summary = '💰 No se encontraron precios para esa fecha.'; }
  else {
    const lines = [];
    for (const rc of roomCalendars) {
      const roomName = roomNames[rc.roomId] || 'Hab.' + rc.roomId;
      const cal = rc.calendar || [];
      if (!cal.length) { lines.push(`• ${roomName}: sin datos`); continue; }
      const entry = cal.find(e => e.day === requestedDate) || cal[0];
      const price = entry.price1 ? `${entry.price1}€/noche` : 'sin precio';
      const numAvail = entry.numAvail !== undefined ? (entry.numAvail > 0 ? '🟢 Libre' : '🔴 Ocupada') : '';
      lines.push(`• ${roomName}: ${price} ${numAvail}`);
    }
    summary = `💰 Precios ${dateLabel(requestedDate)}:\n` + lines.join('\n');
  }

// ── beds24.listBookings ──────────────────────────────────────────────────
} else if (action === 'beds24.listBookings') {
  const bookings = apiResp.data || [];
  if (!bookings.length) { summary = '📋 No hay reservas en el período seleccionado.'; }
  else {
